def rebuild_a2():
    with open("app/data/vocabulary/a1.json", encoding="utf-8") as f:
        a1_words = {w["swedish"].lower() for w in json.load(f)["words"]}

    with open("app/data/vocabulary/a2.json", encoding="utf-8") as f:
        a2_data = json.load(f)

    # Keep unique A2 words not in A1
    kept = [w for w in a2_data["words"] if w["swedish"].lower() not in a1_words]
    kept_set = {w["swedish"].lower() for w in kept}
    print(f"Kept from original A2: {len(kept)}")

    added = []
    skipped = []
    combined_exclusions = a1_words | kept_set

    for word in NEW_WORDS:
        key = word["swedish"].lower()
        if key in combined_exclusions:
            skipped.append(word["swedish"])
            continue
        added.append(word)
        combined_exclusions.add(key)

    all_words = kept + added
    # Re-ID
    for i, w in enumerate(all_words, 1):
        w["id"] = f"a2_{i:03d}"

    a2_data["words"] = all_words

    with open("app/data/vocabulary/a2.json", "w", encoding="utf-8") as f:
        json.dump(a2_data, f, ensure_ascii=False, indent=2)

    print(f"Added new: {len(added)}, Skipped (dupes): {len(skipped)}, Total: {len(all_words)}")
    if skipped:
        print("Skipped:", skipped[:20], "..." if len(skipped) > 20 else "")


rebuild_a2()
